-- Assemblies seed data — auto-generated from Assemblies.xlsx
-- 21,828 items across 7 categories

CREATE TABLE IF NOT EXISTS assemblies (
    id            INTEGER PRIMARY KEY AUTOINCREMENT,
    item_number   TEXT NOT NULL,
    description   TEXT NOT NULL,
    upc           TEXT DEFAULT '',
    cat_number    TEXT DEFAULT '',
    category      TEXT NOT NULL,
    subcategory   TEXT NOT NULL,
    discount      REAL DEFAULT 0,
    unit_price    REAL,
    price_unit    TEXT DEFAULT 'E',
    price_is_quote INTEGER DEFAULT 0,
    price_is_open  INTEGER DEFAULT 0,
    quote_ref      TEXT DEFAULT '',
    labor_1       REAL,
    labor_2       REAL,
    labor_3       REAL,
    labor_4       REAL,
    labor_5       REAL,
    labor_6       REAL,
    labor_unit    TEXT DEFAULT 'E',
    phase         INTEGER DEFAULT 7,
    res_phase     INTEGER DEFAULT 7
);
CREATE INDEX IF NOT EXISTS idx_asm_category    ON assemblies(category);
CREATE INDEX IF NOT EXISTS idx_asm_subcategory ON assemblies(subcategory);
CREATE INDEX IF NOT EXISTS idx_asm_item        ON assemblies(item_number);
CREATE INDEX IF NOT EXISTS idx_asm_desc        ON assemblies(description);












































